class Solution:
    def canTransform(self, start: str, result: str) -> bool:
        # Extract the non-X characters and their positions for both strings
        s_chars = []
        s_indices = []
        for idx, c in enumerate(start):
            if c in {'L', 'R'}:
                s_chars.append(c)
                s_indices.append(idx)

        r_chars = []
        r_indices = []
        for idx, c in enumerate(result):
            if c in {'L', 'R'}:
                r_chars.append(c)
                r_indices.append(idx)

        # Check if the sequences of non-X characters are the same
        if s_chars != r_chars:
            return False

        # Check positions for each corresponding pair
        n = len(s_chars)
        for i in range(n):
            char = s_chars[i]
            start_pos = s_indices[i]
            end_pos = r_indices[i]
            if char == 'L':
                if end_pos > start_pos:
                    return False
            elif char == 'R':
                if end_pos < start_pos:
                    return False
        return True
